/**
 * Tiny markdown subset: bold (**x**), italic (*x*), inline code (`x`), and
 * links ([t](u)). All input is HTML-escaped first; URLs are validated to
 * `http(s):`, `mailto:` or relative paths to keep XSS surface minimal.
 *
 * Limitations (documented in docs/WIDGET.md): no headings, no lists, no code
 * blocks, no images, no tables. Hosts that need richer markdown should
 * publish a custom block renderer for `text` via `registerBlockRenderer`.
 */

const HTML_ESCAPES: Record<string, string> = {
  '&': '&amp;',
  '<': '&lt;',
  '>': '&gt;',
  '"': '&quot;',
  "'": '&#39;',
};

export function escapeHtml(input: string): string {
  return input.replace(/[&<>"']/g, (ch) => HTML_ESCAPES[ch] ?? ch);
}

function safeHref(raw: string): string | null {
  const href = raw.trim();
  if (href === '') return null;
  if (href.startsWith('/') || href.startsWith('#') || href.startsWith('?')) return href;
  if (/^https?:\/\//i.test(href)) return href;
  if (/^mailto:/i.test(href)) return href;
  if (/^tel:/i.test(href)) return href;
  return null;
}

function applyInline(escaped: string): string {
  // Stash inline code with placeholders so its contents are not re-processed by
  // bold/italic/links. Restored at the end.
  const codes: string[] = [];
  let out = escaped.replace(/`([^`\n]+?)`/g, (_m, code: string) => {
    const idx = codes.push(`<code>${code}</code>`) - 1;
    return `�CODE${idx}�`;
  });

  // Links: [text](url). Text is already escaped; href gets validated.
  out = out.replace(/\[([^\]\n]+?)\]\(([^)\s]+?)\)/g, (match: string, text: string, href: string) => {
    const safe = safeHref(href);
    if (!safe) return match;
    return `<a href="${escapeHtml(safe)}" target="_blank" rel="noopener noreferrer">${text}</a>`;
  });
  // Bold: **x**. Then italic: *x* (won't catch inside ** because those were consumed).
  out = out.replace(/\*\*([^*\n]+?)\*\*/g, '<strong>$1</strong>');
  out = out.replace(/(^|[^*])\*([^*\n]+?)\*(?!\*)/g, '$1<em>$2</em>');

  // Restore code placeholders.
  out = out.replace(/�CODE(\d+)�/g, (_m, n: string) => codes[Number(n)] ?? '');
  return out;
}

export function renderMarkdown(input: string): string {
  if (input === '') return '';
  const escaped = escapeHtml(input);
  // Paragraph break on a blank line; otherwise preserve single newlines as <br>.
  const paragraphs = escaped.split(/\n{2,}/).filter((p) => p !== '');
  return paragraphs
    .map((p) => `<p>${applyInline(p).replace(/\n/g, '<br>')}</p>`)
    .join('');
}
